import React, {type FC} from 'react';
import MainUploader from './MainUploader';
import './styles.scss';
import {HTML5Backend} from 'react-dnd-html5-backend';
import {DndProvider} from 'react-dnd';
import type {IFileUploader} from '@lmb-it/kitsconcerto-types';
import {KitsContainer} from "../../_compat";

const FilePicker: FC<IFileUploader<File>> = (props) => {

    const {
        id,
        helperText,
        disabled,
        label,
        errors,
        hideError,
        invalid,
    attached,
    } = props;

    const Element = <DndProvider backend={HTML5Backend}>
        {/*// @ts-ignore*/}
        <MainUploader
            name={id}
            {...props}
        />
    </DndProvider>;

    if (attached) {
        return Element;
    }

    return (
        <DndProvider backend={HTML5Backend}>
            <KitsContainer
                id={id}
                className={'file-picker-component'}
                disabled={disabled}
                label={label}
                hideError={hideError}
                errors={errors}
                invalid={invalid}
                helperText={helperText}
                isFloatedLabel={false}>
                {/*// @ts-ignore*/}
                <MainUploader
                    name={id}
                    {...props}
                />

            </KitsContainer>
        </DndProvider>
    );
};

export default FilePicker;
